        const indexA = businessOrder.indexOf(a.businessLine);
        const indexB = businessOrder.indexOf(b.businessLine);

        if (indexA !== indexB) {
            return indexA - indexB;
        }
        return a.code.localeCompare(b.code);
    });

    // Extract the codes in the sorted order
    const result: string[] = validCoupons.map(c => c.code);

    return result;
}

